INSERT INTO reviews (name, role, text, rating) VALUES
('Александр Волков', 'Предприниматель', 'Арендовал Bentley на выходные — сервис безупречный. Машину доставили вовремя, в идеальном состоянии. Однозначно вернусь.', 5),
('Екатерина Смирнова', 'Event-менеджер', 'Заказывала авто на свадьбу. Всё прошло идеально: подача точно ко времени, водитель вежливый, машина сияла.', 5),
('Дмитрий Козлов', 'Топ-менеджер', 'Пользуюсь AURUM для деловых поездок уже год. Персональный менеджер решает любые вопросы моментально.', 5),
('Мария Орлова', 'Блогер', 'Огромный выбор премиум-авто, честные цены и никаких скрытых платежей. Рекомендую всем друзьям!', 5),
('Сергей Никитин', 'Юрист', 'Брал Range Rover для поездки в горы. Автомобиль в отличном состоянии, всё оформили за 10 минут.', 5);
