INSERT INTO blog_posts (title, category, text, image, published_at) VALUES
('Как выбрать авто для делового визита', 'Гайды', 'Разбираем, какой класс автомобиля произведёт правильное впечатление на партнёров.', 'https://cdn.poehali.dev/projects/10910bdc-8958-4092-a589-39bbc3cf96b8/files/288ceb98-69b6-44ca-b521-191376938449.jpg', '2026-06-28'),
('Топ-5 маршрутов на выходные из Москвы', 'Путешествия', 'Живописные направления, которые лучше всего открывать за рулём премиум-авто.', 'https://cdn.poehali.dev/projects/10910bdc-8958-4092-a589-39bbc3cf96b8/files/232e93f5-ee8f-4ff8-8f5c-459bf622b6fb.jpg', '2026-06-21'),
('Всё о страховке при аренде', 'Советы', 'Какой пакет защиты выбрать и что важно знать перед подписанием договора.', 'https://cdn.poehali.dev/projects/10910bdc-8958-4092-a589-39bbc3cf96b8/files/288ceb98-69b6-44ca-b521-191376938449.jpg', '2026-06-14'),
('Электрокары в аренду: стоит ли?', 'Обзоры', 'Плюсы и минусы аренды электромобилей премиум-класса в большом городе.', 'https://cdn.poehali.dev/projects/10910bdc-8958-4092-a589-39bbc3cf96b8/files/232e93f5-ee8f-4ff8-8f5c-459bf622b6fb.jpg', '2026-06-07');
INSERT INTO faqs (question, answer, sort_order) VALUES
('За сколько времени нужно бронировать авто?', 'Рекомендуем бронировать за 1–2 дня. Но чаще всего мы можем подать автомобиль уже через 2–3 часа после заявки.', 1),
('Есть ли ограничение по пробегу?', 'На тарифах «Премиум» и «VIP» пробег безлимитный. На тарифе «Стандарт» — 200 км в сутки, далее 30 ₽ за км.', 2),
('Как происходит оплата?', 'Оплатить можно банковской картой онлайн, переводом или наличными при получении. Депозит блокируется на карте.', 3),
('Можно ли арендовать авто с водителем?', 'Да, на тарифе VIP доступна услуга личного водителя. Также её можно подключить к любому тарифу за доплату.', 4),
('Что входит в доставку автомобиля?', 'Доставка в пределах города — бесплатно. Привезём авто к дому, в офис, аэропорт или отель в удобное время.', 5),
('Как работает личный кабинет?', 'В личном кабинете вы управляете бронированиями, отслеживаете статус доставки, храните документы и копите бонусы.', 6);
